	// Handle YYYY-MM-DD strings by parsing to end of day in competition's timezone
	let deadlineDate: Date
	if (typeof deadline === "string") {
		const endOfDay = getEndOfDayInTimezone(deadline, timezone)
		if (!endOfDay) {
			// Invalid date string
			return {
				daysRemaining: 0,
				hoursRemaining: 0,
				urgencyLevel: "none",
				message: "",
			}
		}
		deadlineDate = endOfDay
	} else if (typeof deadline === "number") {
		deadlineDate = new Date(deadline)
	} else {
		deadlineDate = deadline
	}
	const diffMs = deadlineDate.getTime() - now.getTime()

	if (diffMs <= 0) {
		return {
			daysRemaining: 0,
			hoursRemaining: 0,
			urgencyLevel: "none",
			message: "Registration closed",
		}
	}

	const hoursRemaining = Math.floor(diffMs / (1000 * 60 * 60))
	const daysRemaining = Math.floor(hoursRemaining / 24)

	if (hoursRemaining <= 24) {
		const hours = hoursRemaining
		return {
			daysRemaining,
			hoursRemaining,
			urgencyLevel: "critical",
			message:
				hours <= 1 ? "Less than 1 hour left!" : `Only ${hours} hours left!`,
		}
	}

	if (daysRemaining <= 3) {
		return {
			daysRemaining,
			hoursRemaining,
			urgencyLevel: "urgent",
			message:
				daysRemaining === 1
					? "Last day to register!"
					: `Only ${daysRemaining} days left!`,
		}
	}

	if (daysRemaining <= 7) {
		return {
			daysRemaining,
			hoursRemaining,
			urgencyLevel: "normal",
			message: `${daysRemaining} days left to register`,
		}
	}

	return {
		daysRemaining,
		hoursRemaining,
		urgencyLevel: "none",
		message: "",
	}
}

