														: "View Team"
													: "View Registration"}
											</a>
										</Button>
									)}
								</>
							)}

							{/* Register for Another Division - shown when registered AND registration is open */}
							{registrationOpen && (
								<Button asChild variant="outline" size="sm" className="w-full">
