		})
		.from(competitionRegistrationsTable)
		.where(eq(competitionRegistrationsTable.eventId, data.competitionId))
		.orderBy(asc(competitionRegistrationsTable.registeredAt))

	if (registrations.length === 0) {
		return { registrations: [] }
	}

	// Fetch users
	const userIds = [...new Set(registrations.map((r) => r.userId))]
	const users =
		userIds.length > 0
			? await db
					.select({
						id: userTable.id,
						firstName: userTable.firstName,
						lastName: userTable.lastName,
					})
					.from(userTable)
					.where(inArray(userTable.id, userIds))
			: []
	const userMap = new Map(users.map((u) => [u.id, u]))

	// Fetch divisions
	const divisionIds = [
		...new Set(
			registrations
				.map((r) => r.divisionId)
				.filter((id): id is string => id !== null),
		),
	]
	const divisions =
		divisionIds.length > 0
			? await db
					.select({

		timeCap: result.workoutTimeCap,
		repsPerRound: result.workoutRepsPerRound,
		roundsToScore: result.workoutRoundsToScore,
	},
}

// Get all registrations for this competition (with optional division filter)
const registrations = await db
	.select({
		registration: competitionRegistrationsTable,
		user: userTable,
