	})
	.from(competitionRegistrationsTable)
	.innerJoin(
		userTable,
		eq(competitionRegistrationsTable.userId, userTable.id),
	)
	.leftJoin(
		scalingLevelsTable,
		eq(competitionRegistrationsTable.divisionId, scalingLevelsTable.id),
	)
	.where(
		and(
			eq(competitionRegistrationsTable.eventId, data.competitionId),
			...(data.divisionId
				? [eq(competitionRegistrationsTable.divisionId, data.divisionId)]
				: []),
		),
	)

const filteredRegistrations = registrations

// Get existing scores for this event
const userIds = filteredRegistrations.map((r) => r.user.id)
const existingScores =
	userIds.length > 0
		? await db
				.select()
				.from(scoresTable)

	}
	return { events: [], totalPublishedCount: 0, totalCombinations: 0 }
}

// Get registrations per division
const divisionIds = divisions.map((d) => d.id)
const registrationCounts = await db
	.select({
		divisionId: competitionRegistrationsTable.divisionId,
		count: sql<number>`cast(count(*) as unsigned)`,
	})
	.from(competitionRegistrationsTable)
	.where(
		and(
			eq(competitionRegistrationsTable.eventId, data.competitionId),
			inArray(competitionRegistrationsTable.divisionId, divisionIds),
		),
	)
	.groupBy(competitionRegistrationsTable.divisionId)

const registrationCountMap = new Map<string, number>()
for (const row of registrationCounts) {
	if (row.divisionId) {
		registrationCountMap.set(row.divisionId, row.count)
	}
}

// Get the competition's programming track to find all events
const [track] = await db
	.select({ id: programmingTracksTable.id })
	.from(programmingTracksTable)
	.where(eq(programmingTracksTable.competitionId, data.competitionId))

if (!track) {
	// No events yet
	if (data.eventId) {
