				schedulePublishedAt: data.publish ? now : null,
				updatedAt: now,
			})
			.where(eq(competitionHeatsTable.trackWorkoutId, data.trackWorkoutId))

		return {
			success: true,
			updatedCount: heats.length,
			schedulePublishedAt: data.publish ? now : null,
		}
	})

