/**
 * Check if a venue has any heats assigned
 * Used for delete confirmation
 */
export const getVenueHeatCountFn = createServerFn({ method: "GET" })
	.inputValidator((data: unknown) =>
		z.object({ venueId: z.string().min(1) }).parse(data),
