})

const updateAssignmentInputSchema = z.object({
	assignmentId: z.string().min(1, "Assignment ID is required"),
	laneNumber: z.number().int().min(1, "Lane number must be at least 1"),
})

const moveAssignmentInputSchema = z.object({
