/**
 * Get spots available for a division
 * Used for registration validation
 */
export const getDivisionSpotsAvailableFn = createServerFn({ method: "GET" })
	.inputValidator((data: unknown) =>
		getDivisionSpotsAvailableInputSchema.parse(data),
	)
	.handler(async ({ data }) => {
		const db = getDb()

		// Get competition for default capacity
		const competition = await db.query.competitionsTable.findFirst({
			where: eq(competitionsTable.id, data.competitionId),
		})

		if (!competition) {
			throw new Error("Competition not found")
		}

		// Get division config for override
		const divisionConfig = await db.query.competitionDivisionsTable.findFirst({
			where: and(
				eq(competitionDivisionsTable.competitionId, data.competitionId),
				eq(competitionDivisionsTable.divisionId, data.divisionId),
			),
		})

		// Get registration count and pending purchases (reservations)
		const [registrations, pendingPurchases] = await Promise.all([
			// Count confirmed registrations (exclude removed)
			db
				.select({ count: count() })
				.from(competitionRegistrationsTable)
				.where(
					and(
						eq(competitionRegistrationsTable.divisionId, data.divisionId),
						eq(competitionRegistrationsTable.eventId, data.competitionId),
						ne(
							competitionRegistrationsTable.status,
							REGISTRATION_STATUS.REMOVED,
						),
					),
				),
			// Count pending purchases (reservations) - excludes specified purchaseId to avoid self-blocking
			db
				.select({ count: count() })
				.from(commercePurchaseTable)
				.where(
					and(
						eq(commercePurchaseTable.competitionId, data.competitionId),
						eq(commercePurchaseTable.divisionId, data.divisionId),
						eq(commercePurchaseTable.status, COMMERCE_PURCHASE_STATUS.PENDING),
						// Exclude specific purchase if provided (for webhook re-check)
						data.excludePurchaseId
							? sql`${commercePurchaseTable.id} != ${data.excludePurchaseId}`
							: undefined,
					),
				),
		])

		const confirmedCount = Number(registrations[0]?.count ?? 0)
		const pendingCount = Number(pendingPurchases[0]?.count ?? 0)
		const capacity = calculateDivisionCapacity({
			registrationCount: confirmedCount,
			pendingCount,
			divisionMaxSpots: divisionConfig?.maxSpots,
			competitionDefaultMax: competition.defaultMaxSpotsPerDivision,
		})

		return {
			maxSpots: capacity.effectiveMax,
			registered: capacity.totalOccupied,
			confirmedCount,
			pendingCount,
			available: capacity.spotsAvailable,
			isFull: capacity.isFull,
		}
	})

/**
 * Athlete Score Submission Server Functions
 *
 * Server functions for athletes to submit their own scores in online competitions.
 * Includes validation for submission windows and score format based on workout scheme.
 *
 * OBSERVABILITY:
 * - All athlete score submissions are logged with user and event IDs
 * - Submission window status checks are logged
 * - Validation failures tracked for debugging
 */

import { createServerFn } from "@tanstack/react-start"
import { and, eq } from "drizzle-orm"
import { z } from "zod"
import { getDb } from "@/db"
import {
	addRequestContextAttribute,
	logEntityUpdated,
	logError,
	logInfo,
	logWarning,
	updateRequestContext,
} from "@/lib/logging"
import {
	competitionEventsTable,
	competitionRegistrationsTable,
	competitionsTable,
} from "@/db/schemas/competitions"
import {
	programmingTracksTable,
	trackWorkoutsTable,
} from "@/db/schemas/programming"
import { scoresTable } from "@/db/schemas/scores"
import type { TiebreakScheme } from "@/db/schemas/workouts"
import { workouts } from "@/db/schemas/workouts"
import {
	computeSortKey,
	encodeScore,
	getDefaultScoreType,
	parseScore,
	type ScoreType,
	STATUS_ORDER,
	sortKeyToString,
	type WorkoutScheme,
} from "@/lib/scoring"
import { getSessionFromCookie } from "@/utils/auth"

// ============================================================================
// Types
// ============================================================================

export interface AthleteScoreSubmission {
	trackWorkoutId: string
	score: string
	status: "scored" | "cap"
	/** Secondary score (reps at cap) for time-capped workouts */
	secondaryScore?: string
	/** Tiebreak score if applicable */
	tiebreakScore?: string
}

export interface SubmissionWindowStatus {
	isOpen: boolean
	opensAt: string | null
	closesAt: string | null
	reason?: string
}

export interface AthleteEventScore {
	scoreId: string | null
	scoreValue: number | null
	displayScore: string | null
	status: string | null
	secondaryValue: number | null
	tiebreakValue: number | null
	submittedAt: Date | null
}

// ============================================================================
// Input Schemas
// ============================================================================

const submitScoreInputSchema = z.object({
	competitionId: z.string().min(1),
	trackWorkoutId: z.string().min(1),
	score: z.string().min(1, "Score is required"),
	status: z.enum(["scored", "cap"]),
	secondaryScore: z.string().optional(),
	tiebreakScore: z.string().optional(),
})

const getScoreInputSchema = z.object({
	competitionId: z.string().min(1),
	trackWorkoutId: z.string().min(1),
})

const getSubmissionWindowInputSchema = z.object({
	competitionId: z.string().min(1),
	trackWorkoutId: z.string().min(1),
})

// ============================================================================
// Helper Functions
// ============================================================================

/**
 * Map status to the simplified type for scores table.
 */
function getStatusOrder(status: "scored" | "cap"): number {
	switch (status) {
		case "scored":
			return STATUS_ORDER.scored
		case "cap":
			return STATUS_ORDER.cap
		default:
			return STATUS_ORDER.scored
	}
}

/**
 * Check if current time is within the event's submission window.
 */
async function checkSubmissionWindow(
	competitionId: string,
	trackWorkoutId: string,
): Promise<SubmissionWindowStatus> {
	const db = getDb()

	// Get competition type
	const [competition] = await db
		.select({
			competitionType: competitionsTable.competitionType,
		})
		.from(competitionsTable)
		.where(eq(competitionsTable.id, competitionId))
		.limit(1)

	if (!competition) {
		return {
			isOpen: false,
			opensAt: null,
			closesAt: null,
			reason: "Competition not found",
		}
	}

	// Only check submission windows for online competitions
	if (competition.competitionType !== "online") {
		return {
			isOpen: false,
			opensAt: null,
			closesAt: null,
			reason: "This is not an online competition",
		}
	}

	// Get competition event with submission window
	const [event] = await db
		.select({
			submissionOpensAt: competitionEventsTable.submissionOpensAt,
			submissionClosesAt: competitionEventsTable.submissionClosesAt,
		})
		.from(competitionEventsTable)
		.where(
			and(
				eq(competitionEventsTable.competitionId, competitionId),
				eq(competitionEventsTable.trackWorkoutId, trackWorkoutId),
			),
		)
		.limit(1)

	// If no event record exists, submission not configured
	if (!event) {
		return {
			isOpen: false,
			opensAt: null,
			closesAt: null,
			reason: "Submission window not configured",
		}
	}

	// If no submission window is configured, submission not allowed
	if (!event.submissionOpensAt || !event.submissionClosesAt) {
		return {
			isOpen: false,
			opensAt: null,
			closesAt: null,
			reason: "Submission window not configured",
		}
	}

	// Check if current time is within the window
	const now = new Date()
	const opensAt = new Date(event.submissionOpensAt)
	const closesAt = new Date(event.submissionClosesAt)

	if (now < opensAt) {
		return {
			isOpen: false,
			opensAt: event.submissionOpensAt,
			closesAt: event.submissionClosesAt,
			reason: "Submission window has not opened yet",
		}
	}

	if (now > closesAt) {
		return {
			isOpen: false,
			opensAt: event.submissionOpensAt,
			closesAt: event.submissionClosesAt,
			reason: "Submission window has closed",
		}
	}

	return {
		isOpen: true,
		opensAt: event.submissionOpensAt,
		closesAt: event.submissionClosesAt,
	}
}

